package entity

import (
	"math"
	"testing"
)

// TestUnitOrderCalculateTotalEdgeCases – дополнительные edge‑case‑тесты
// для метода Order.CalculateTotal().  В проекте уже есть тесты
// TestUnitOrderCalculateTotal, TestUnitOrderCalculateTotalEmpty,
// TestUnitOrderCalculateTotalSingleItem, TestUnitOrderCalculateTotalLargeOrder
// и TestUnitOrderCalculateTotalFloatPrecision, поэтому здесь проверяем
// сценарии, которые пока не покрыты:
//
//   1. Отрицательная цена у позиции (Validate() не проверяет цену,
//      а только Quantity и ProductID, поэтому CalculateTotal() должна
//      корректно суммировать отрицательные значения).
//   2. Нулевая количество у позиции – тоже не проверяется в Validate(),
//      но умножение должно дать 0.
//   3. Смешанные положительные и отрицательные цены.
//   4. Цена NaN – результат должен стать NaN.
//   5. Цена +Inf/‑Inf – результат должен стать +Inf/‑Inf соответственно.
//
// Для сравнения с обычными числами используем небольшую погрешность
// (1e-9), а для NaN/Inf проверяем специальные свойства из пакета math.

func TestUnitOrderCalculateTotalEdgeCases(t *testing.T) {
	const eps = 1e-9

	tests := []struct {
		name      string
		items     []OrderItem
		wantTotal float64
		wantNaN   bool
		wantInf   bool // +Inf
	}{
		{
			name: "NegativePrice",
			items: []OrderItem{
				{ProductID: 1, Quantity: 2, Price: -150.0},
				{ProductID: 2, Quantity: 1, Price: 300.0},
			},
			// (-150*2) + (300*1) = 0
			wantTotal: 0.0,
		},
		{
			name: "ZeroQuantity",
			items: []OrderItem{
				{ProductID: 1, Quantity: 0, Price: 123.45},
				{ProductID: 2, Quantity: 5, Price: 10.0},
			},
			// (0*123.45) + (5*10) = 50
			wantTotal: 50.0,
		},
		{
			name: "MixedPositiveNegative",
			items: []OrderItem{
				{ProductID: 1, Quantity: 3, Price: 100.0},
				{ProductID: 2, Quantity: 2, Price: -50.0},
				{ProductID: 3, Quantity: 1, Price: 25.0},
			},
			// (3*100) + (2*-50) + (1*25) = 275
			wantTotal: 275.0,
		},
		{
			name: "NaNPrice",
			items: []OrderItem{
				{ProductID: 1, Quantity: 1, Price: math.NaN()},
				{ProductID: 2, Quantity: 2, Price: 10.0},
			},
			wantNaN: true,
		},
		{
			name: "InfinityPrice",
			items: []OrderItem{
				{ProductID: 1, Quantity: 1, Price: math.Inf(1)},
				{ProductID: 2, Quantity: 3, Price: 5.0},
			},
			wantInf: true,
		},
	}

	for _, tt := range tests {
		tt := tt // capture range variable
		t.Run(tt.name, func(t *testing.T) {
			o := Order{
				Items: tt.items,
			}
			o.CalculateTotal()

			if tt.wantNaN {
				if !math.IsNaN(o.Total) {
					t.Fatalf("expected Total to be NaN, got %v", o.Total)
				}
				return
			}
			if tt.wantInf {
				if !math.IsInf(o.Total, +1) {
					t.Fatalf("expected Total to be +Inf, got %v", o.Total)
				}
				return
			}
			if diff := math.Abs(o.Total - tt.wantTotal); diff > eps {
				t.Fatalf("total mismatch: want %v, got %v (diff %v)", tt.wantTotal, o.Total, diff)
			}
		})
	}
}
```

### Что делает тест

| Подтест | Сценарий | Ожидаемый результат |
|---------|----------|----------------------|
| **NegativePrice** | В заказе присутствует позиция с отрицательной ценой. | Сумма корректно учитывает отрицательное значение (в примере 0). |
| **ZeroQuantity** | Одна из позиций имеет количество 0. | Вклад позиции в итоговую сумму 0, остальные считаются нормально. |
| **MixedPositiveNegative** | Смешанные положительные и отрицательные цены. | Итоговая сумма – арифметическое сложение всех `price*quantity`. |
| **NaNPrice** | Цена позиции `NaN`. | Итоговая сумма тоже `NaN` (поведение IEEE 754). |
| **InfinityPrice** | Цена позиции `+Inf`. | Итоговая сумма – `+Inf`, независимо от остальных позиций. |

Эти кейсы **не дублируют** уже существующие тесты (они покрывают только обычные положительные цены, пустой заказ, один элемент, большие количества и обычную плавающую точность).  

Тест использует таблицу (`tests []struct{...}`) и `t.Run` – такой же стиль, как в остальных unit‑тестах проекта (см. `TestUnitProductValidate`, `TestUnitNewsItemSummary` и др.).  

Запуск всех тестов (`go test ./...`) покажет, что новый набор проходит без конфликтов и повышает покрытие метода `Order.CalculateTotal()` до 100 % для edge‑case‑сценариев.

