		InStock:    true,
	}
	createdProd := createProduct(t, baseURL, prod)
	if createdProd.ID == 0 {
		t.Fatalf("expected product ID to be set, got 0")
	}
	if createdProd.Price != prod.Price {
		t.Fatalf("product price mismatch: want %v, got %v", prod.Price, createdProd.Price)
	}

	// -----------------------------------------------------------------------
	// 4️⃣  Оформляем заказ (один товар, количество 2 → total = 640).
	// -----------------------------------------------------------------------
	orderReq := entity.Order{
