	if createdOrder.Total != 640.0 {
		t.Fatalf("order total mismatch: want 640, got %v", createdOrder.Total)
	}
	if createdOrder.Status != entity.OrderStatusNew {
		t.Fatalf("order status after creation must be %s, got %s",
			entity.OrderStatusNew, createdOrder.Status)
	}

	// -----------------------------------------------------------------------
	// 5️⃣  Обрабатываем (process) заказ.
	// -----------------------------------------------------------------------
	processURL := baseURL + "/orders/" + strconv.FormatInt(createdOrder.ID, 10) + "/process"
	resp := doRequest(t, http.MethodPost, processURL, nil)
	if resp.StatusCode != http.StatusOK {
		t.Fatalf("process request returned %d, want %d", resp.StatusCode, http.StatusOK)
	}
	// Перезапрашиваем, чтобы убедиться в изменённом статусе.
	updatedOrder := getOrderByID(t, baseURL, createdOrder.ID)
	if updatedOrder.Status != entity.OrderStatusProcessing {
		t.Fatalf("order status after process must be %s, got %s",
