	// -----------------------------------------------------------------------
	// 6️⃣  Завершаем (complete) заказ.
	// -----------------------------------------------------------------------
	completeURL := baseURL + "/orders/" + strconv.FormatInt(createdOrder.ID, 10) + "/complete"
	resp = doRequest(t, http.MethodPost, completeURL, nil)
	if resp.StatusCode != http.StatusOK {
		t.Fatalf("complete request returned %d, want %d", resp.StatusCode, http.StatusOK)
