func doRequest(t *testing.T, method, url string, body interface{}) *http.Response {
	t.Helper()
	var req *http.Request
	var err error
	if body != nil {
		b, err := json.Marshal(body)
		if err != nil {
			t.Fatalf("json marshal failed: %v", err)
		}
		req, err = http.NewRequest(method, url, strings.NewReader(string(b)))
		req.Header.Set("Content-Type", "application/json")
	} else {
		req, err = http.NewRequest(method, url, nil)
	}
	if err != nil {
		t.Fatalf("creating request: %v", err)
	}
	client := &http.Client{}
	resp, err := client.Do(req)
	if err != nil {
		t.Fatalf("do request: %v", err)
	}
	return resp
}

// getOrderByID – GET /orders/{id}
func getOrderByID(t *testing.T, baseURL string, id int64) *entity.Order {
	t.Helper()
	url := baseURL + "/orders/" + strconv.FormatInt(id, 10)
	resp, err := http.Get(url)
	if err != nil {
		t.Fatalf("GET order %d failed: %v", id, err)
	}
	defer resp.Body.Close()
	if resp.StatusCode != http.StatusOK {
		t.Fatalf("GET order %d returned %d, want %d", id, resp.StatusCode, http.StatusOK)
	}
	var out struct {
		Order *entity.Order `json:"order"`
	}
	decodeBody(t, resp, &out)
	if out.Order == nil {
		t.Fatalf("order payload is nil")
	}
	return out.Order
}
