// entity/product_test.go
type validateCase struct {
    name      string
    product   Product
    wantError error
}

func TestUnitProductValidate(t *testing.T) {
    cases := []validateCase{
        {"empty_name", Product{Name: "", Price: 10, CategoryID: 1}, ErrEmptyName},
        {"negative_price", Product{Name: "Latte", Price: -5, CategoryID: 1}, ErrNegativePrice},
        {"zero_price_valid", Product{Name: "Latte", Price: 0, CategoryID: 1}, nil},
        // … остальные 12 кейсов …
    }

    for _, tc := range cases {
        tc := tc // capture range variable
        t.Run(tc.name, func(t *testing.T) {
            t.Parallel()               // <-- теперь каждый sub‑test может работать параллельно
            if err := tc.product.Validate(); !errors.Is(err, tc.wantError) {
                t.Fatalf("expected %v, got %v", tc.wantError, err)
            }
        })
    }
}
```

