```go
package entity

import (
	"math"
	"testing"
)

// TestUnitOrderCalculateTotalEdgeCases проверяет метод Order.CalculateTotal()
// на «крайних» (edge) ситуациях, которые пока не покрыты другими тестами
// (TestUnitOrderCalculateTotal*, TestUnitOrderCalculateTotalFloatPrecision, …).
//
// Сценарии:
//
// 1. Товар с нулевым количеством – результат должен игнорировать такой элемент.
// 2. Товар с отрицательным количеством – метод просто суммирует, без валидации.
// 3. Товар с отрицательной ценой – тоже просто суммируется.
// 4. Очень большая цена, при которой итоговое значение переходит в +Inf.
// 5. Цена NaN – итоговая сумма тоже должна стать NaN (поведение IEEE‑754).
// 6. Смешанный набор, где некоторые элементы дают обычный результат, а
//    остальные – экстремальные (Inf/NaN). Проверяем, что итоговое значение
//    соответствует ожидаемому (Inf/NaN «доминирует»).
func TestUnitOrderCalculateTotalEdgeCases(t *testing.T) {
	tests := []struct {
		name     string
		items    []OrderItem
		expected float64 // если math.IsInf/IsNaN – проверяем соответствующим способом
	}{
		{
			name: "zero_quantity",
			items: []OrderItem{
				{ProductID: 1, Quantity: 0, Price: 123.45},
				{ProductID: 2, Quantity: 3, Price: 10.0},
			},
			// 0*123.45 + 3*10 = 30
			expected: 30.0,
		},
		{
			name: "negative_quantity",
			items: []OrderItem{
				{ProductID: 1, Quantity: -2, Price: 50.0},
				{ProductID: 2, Quantity: 5, Price: 20.0},
			},
			// -2*50 + 5*20 = -100 + 100 = 0
			expected: 0.0,
		},
		{
			name: "negative_price",
			items: []OrderItem{
				{ProductID: 1, Quantity: 2, Price: -30.0},
				{ProductID: 2, Quantity: 1, Price: 80.0},
			},
			// 2*(-30) + 1*80 = -60 + 80 = 20
			expected: 20.0,
		},
		{
			name: "huge_price_overflow_to_inf",
			items: []OrderItem{
				{ProductID: 1, Quantity: 1, Price: math.MaxFloat64},
				{ProductID: 2, Quantity: 2, Price: 1.0},
			},
			// MaxFloat64 + 2*1 overflows → +Inf
			expected: math.Inf(1),
		},
		{
			name: "price_nan_propagates",
			items: []OrderItem{
				{ProductID: 1, Quantity: 1, Price: math.NaN()},
				{ProductID: 2, Quantity: 3, Price: 10.0},
			},
			// NaN + 30 = NaN
			expected: math.NaN(),
		},
		{
			name: "mixed_inf_and_nan",
			items: []OrderItem{
				{ProductID: 1, Quantity: 1, Price: math.Inf(1)},
				{ProductID: 2, Quantity: 1, Price: math.NaN()},
			},
			// Inf + NaN = NaN (по правилам IEEE‑754)
			expected: math.NaN(),
		},
	}

	const eps = 1e-9 // допуск для сравнения обычных float‑ов

	for _, tt := range tests {
		tt := tt // захватываем переменную для параллельных под‑тестов
		t.Run(tt.name, func(t *testing.T) {
			t.Parallel()

			o := Order{
				Items: tt.items,
			}
			o.CalculateTotal()

			got := o.Total

			switch {
			case math.IsInf(tt.expected, 1):
				if !math.IsInf(got, 1) {
					t.Fatalf("expected +Inf, got %v", got)
				}
			case math.IsInf(tt.expected, -1):
				if !math.IsInf(got, -1) {
					t.Fatalf("expected -Inf, got %v", got)
				}
			case math.IsNaN(tt.expected):
				if !math.IsNaN(got) {
					t.Fatalf("expected NaN, got %v", got)
				}
			default:
				if diff := math.Abs(got - tt.expected); diff > eps {
					t.Fatalf("total mismatch: want %v, got %v (diff %v)", tt.expected, got, diff)
				}
			}
		})
	}
}
```

### Что делает тест

| № | Сценарий | Что проверяется |
|---|----------|-----------------|
| 1 | `zero_quantity` | Элемент с `Quantity == 0` не влияет на итоговую сумму. |
| 2 | `negative_quantity` | Метод **не** валидирует количество – просто суммирует, получаем ожидаемый (может быть 0). |
| 3 | `negative_price` | Отрицательная цена тоже просто участвует в расчёте. |
| 4 | `huge_price_overflow_to_inf` | При переполнении `float64` итоговое значение должно стать `+Inf`. |
| 5 | `price_nan_propagates` | Если хотя бы один элемент имеет `NaN`‑цену, итоговая сумма тоже `NaN`. |
| 6 | `mixed_inf_and_nan` | При комбинации `Inf` и `NaN` результатом является `NaN` (правило IEEE‑754). |

### Почему тест не дублирует существующие

* **Тесты уже покрывают** обычные суммы, пустой заказ, один элемент, большую нагрузку и погрешность `float64`.  
* **Новые сценарии** – нулевое/отрицательное количество, отрицательная цена, переполнение до `Inf`, NaN‑цену и их комбинацию – **не присутствуют** в текущем наборе (`TestUnitOrderCalculateTotal*`).  
