func TestIntegrationFullFlow_CreateCategoryAddProductOrderProcessComplete(t *testing.T) {
	// --------------------------------------------------------------------
	// 1️⃣  Подготовка инфраструктуры (чистая in‑memory SQLite + миграции)
	// --------------------------------------------------------------------
	uc := setupUC(t) // возвращает структуру с 4‑мя use‑case’ами

	// --------------------------------------------------------------------
	// 2️⃣  Создаём категорию
	// --------------------------------------------------------------------
	cat := &entity.Category{
