		Slug: "coffee",
	}
	err := uc.CategoryUC.Create(context.Background(), cat)
	require.NoError(t, err, "создание категории не должно вернуть ошибку")
	require.NotZero(t, cat.ID, "ID категории должно быть присвоено репозиторием")

	// --------------------------------------------------------------------
	// 3️⃣  Добавляем товар в только‑что созданную категорию
	// --------------------------------------------------------------------
	prod := &entity.Product{
		CategoryID:  cat.ID,
		Name:        "Espresso",
		Description: "Strong black coffee",
		Price:       300.0,
		ImageURL:    "",
		InStock:     true,
	}
	err = uc.ProductUC.Create(context.Background(), prod)
	require.NoError(t, err, "создание продукта не должно вернуть ошибку")
	require.NotZero(t, prod.ID, "ID продукта должно быть присвоено репозиторием")

	// --------------------------------------------------------------------
	// 4️⃣  Оформляем заказ (2 × Espresso)
	// --------------------------------------------------------------------
	order := &entity.Order{
		CustomerID: "alice@example.com",
		Items: []entity.OrderItem{
			{
				ProductID: prod.ID,
				Quantity:  2,
