	err = uc.OrderUC.Create(context.Background(), order)
	require.NoError(t, err, "создание заказа не должно вернуть ошибку")
	require.NotZero(t, order.ID, "ID заказа должно быть присвоено репозиторием")

	// Проверяем, что цена продукта подставилась в элемент заказа
	require.Len(t, order.Items, 1, "в заказе должен быть ровно один элемент")
	assert.Equal(t, prod.Price, order.Items[0].Price, "цена в OrderItem должна совпадать с ценой продукта")

	// Проверяем расчёт Total
	expectedTotal := prod.Price * 2 // 300 * 2 = 600
	assert.InDelta(t, expectedTotal, order.Total, 0.0001, "общая сумма заказа должна быть рассчитана корректно")
	assert.Equal(t, entity.OrderStatusNew, order.Status, "новый заказ должен иметь статус 'new'")

	// --------------------------------------------------------------------
	// 5️⃣  Переводим в статус *processing*
	// --------------------------------------------------------------------
	err = uc.OrderUC.Process(context.Background(), order.ID)
